// Extract text from uploaded file or body text
const input = $input.first().json;
let text = '';

if (input.body && input.body.text) {
  text = input.body.text;
} else if (input.body && input.body.url) {
  // Will be fetched in next node
  return [{ json: { text: '', url: input.body.url, mode: 'url' } }];
} else {
  text = JSON.stringify(input.body).substring(0, 10000);
}

// Chunk long documents
const maxChunk = 4000;
const chunks = [];
for (let i = 0; i < text.length; i += maxChunk) {
  chunks.push(text.substring(i, i + maxChunk));
}

return [{ json: { text: text.substring(0, 8000), chunks: chunks.length, mode: 'text' } }];

const summary = JSON.parse($('Summarize Document (Ollama)').first().json.data).response;
const qa = JSON.parse($('Generate Q&A (Ollama)').first().json.data).response;

return [{
  json: {
    summary: summary,
    questions_and_answers: qa,
    document_length: $('Extract & Prepare Text').first().json.text.length,
    chunks_processed: $('Extract & Prepare Text').first().json.chunks,
    processed_at: new Date().toISOString()
  }
}];
